import LocalAuthentication
import UIKit

class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    
    private let context = LAContext()
    private let userDefaults = UserDefaults.standard
    private let biometricEnabledKey = "biometricAuthEnabled"
    private let userAuthenticatedKey = "userAuthenticated"
    
    private init() {}
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        
        if #available(iOS 11.0, *) {
            switch context.biometryType {
            case .faceID:
                return .faceID
            case .touchID:
                return .touchID
            case .none:
                return .none
            @unknown default:
                return .none
            }
        } else {
            return .touchID
        }
    }
    
    var isBiometricAvailable: Bool {
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil)
    }
    
    var isBiometricEnabled: Bool {
        get {
            return userDefaults.bool(forKey: biometricEnabledKey)
        }
        set {
            userDefaults.set(newValue, forKey: biometricEnabledKey)
        }
    }
    
    var isUserAuthenticated: Bool {
        get {
            return userDefaults.bool(forKey: userAuthenticatedKey)
        }
        set {
            userDefaults.set(newValue, forKey: userAuthenticatedKey)
        }
    }
    
    func authenticateUser(completion: @escaping (Bool, Error?) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Enter Password"
        
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            completion(false, error)
            return
        }
        
        let reason = biometricType == .faceID ? "Authenticate with Face ID" : "Authenticate with Touch ID"
        
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, localizedReason: reason) { success, error in
            DispatchQueue.main.async {
                if success {
                    self.isUserAuthenticated = true
                    completion(true, nil)
                } else {
                    completion(false, error)
                }
            }
        }
    }
    
    func logout() {
        isUserAuthenticated = false
    }
}

